import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { 
  FileText, 
  Plus, 
  Clock, 
  CheckCircle, 
  AlertCircle,
  TrendingUp,
  Calendar
} from 'lucide-react';

const UserDashboard = () => {
  const { user, api } = useAuth();
  const [stats, setStats] = useState({
    total: 0,
    pending: 0,
    inProgress: 0,
    resolved: 0,
  });
  const [recentComplaints, setRecentComplaints] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      setLoading(true);

      // Fetch user's complaints
      const complaintsResponse = await api.get('/complaints?size=5&sortBy=createdAt&sortDir=desc');
      const complaints = complaintsResponse.data.content || complaintsResponse.data;

      // Calculate stats
      const stats = complaints.reduce((acc, complaint) => {
        acc.total++;
        switch (complaint.status) {
          case 'PENDING':
            acc.pending++;
            break;
          case 'IN_PROGRESS':
            acc.inProgress++;
            break;
          case 'RESOLVED':
            acc.resolved++;
            break;
        }
        return acc;
      }, { total: 0, pending: 0, inProgress: 0, resolved: 0 });

      setStats(stats);
      setRecentComplaints(complaints);
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'PENDING':
        return <Clock className="h-4 w-4 text-warning-600" />;
      case 'IN_PROGRESS':
        return <AlertCircle className="h-4 w-4 text-primary-600" />;
      case 'RESOLVED':
        return <CheckCircle className="h-4 w-4 text-success-600" />;
      default:
        return <Clock className="h-4 w-4 text-gray-600" />;
    }
  };

  const getStatusClass = (status) => {
    switch (status) {
      case 'PENDING':
        return 'status-pending';
      case 'IN_PROGRESS':
        return 'status-in-progress';
      case 'RESOLVED':
        return 'status-resolved';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const getPriorityClass = (priority) => {
    switch (priority) {
      case 'LOW':
        return 'priority-low';
      case 'MEDIUM':
        return 'priority-medium';
      case 'HIGH':
        return 'priority-high';
      case 'URGENT':
        return 'priority-urgent';
      default:
        return 'priority-medium';
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Welcome Section */}
      <div className="bg-gradient-to-r from-primary-600 to-primary-700 rounded-xl p-6 text-white">
        <h1 className="text-2xl font-bold mb-2">
          Welcome back, {user?.name}!
        </h1>
        <p className="text-primary-100">
          Manage your infrastructure complaints efficiently
        </p>
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <Link
          to="/complaints/new"
          className="card hover:shadow-lg transition-shadow duration-200 group"
        >
          <div className="flex items-center space-x-4">
            <div className="flex-shrink-0">
              <div className="p-3 bg-primary-100 rounded-lg group-hover:bg-primary-200 transition-colors">
                <Plus className="h-6 w-6 text-primary-600" />
              </div>
            </div>
            <div>
              <p className="text-sm font-medium text-gray-900">New Complaint</p>
              <p className="text-xs text-gray-500">Create a new complaint</p>
            </div>
          </div>
        </Link>

        <Link
          to="/complaints"
          className="card hover:shadow-lg transition-shadow duration-200 group"
        >
          <div className="flex items-center space-x-4">
            <div className="flex-shrink-0">
              <div className="p-3 bg-secondary-100 rounded-lg group-hover:bg-secondary-200 transition-colors">
                <FileText className="h-6 w-6 text-secondary-600" />
              </div>
            </div>
            <div>
              <p className="text-sm font-medium text-gray-900">All Complaints</p>
              <p className="text-xs text-gray-500">View all your complaints</p>
            </div>
          </div>
        </Link>
      </div>

      {/* Statistics */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="card">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">Total Complaints</p>
              <p className="text-2xl font-bold text-gray-900">{stats.total}</p>
            </div>
            <div className="p-3 bg-blue-100 rounded-lg">
              <FileText className="h-6 w-6 text-blue-600" />
            </div>
          </div>
        </div>

        <div className="card">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">Pending</p>
              <p className="text-2xl font-bold text-warning-600">{stats.pending}</p>
            </div>
            <div className="p-3 bg-warning-100 rounded-lg">
              <Clock className="h-6 w-6 text-warning-600" />
            </div>
          </div>
        </div>

        <div className="card">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">In Progress</p>
              <p className="text-2xl font-bold text-primary-600">{stats.inProgress}</p>
            </div>
            <div className="p-3 bg-primary-100 rounded-lg">
              <AlertCircle className="h-6 w-6 text-primary-600" />
            </div>
          </div>
        </div>

        <div className="card">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">Resolved</p>
              <p className="text-2xl font-bold text-success-600">{stats.resolved}</p>
            </div>
            <div className="p-3 bg-success-100 rounded-lg">
              <CheckCircle className="h-6 w-6 text-success-600" />
            </div>
          </div>
        </div>
      </div>

      {/* Recent Complaints */}
      <div className="card">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-semibold text-gray-900">Recent Complaints</h2>
          <Link
            to="/complaints"
            className="text-sm text-primary-600 hover:text-primary-500 font-medium"
          >
            View All
          </Link>
        </div>

        {recentComplaints.length === 0 ? (
          <div className="text-center py-8">
            <FileText className="h-12 w-12 text-gray-400 mx-auto mb-4" />
            <p className="text-gray-500">No complaints yet</p>
            <Link
              to="/complaints/new"
              className="btn btn-primary mt-4"
            >
              Create Your First Complaint
            </Link>
          </div>
        ) : (
          <div className="space-y-4">
            {recentComplaints.map((complaint) => (
              <div
                key={complaint.id}
                className="border border-gray-200 rounded-lg p-4 hover:bg-gray-50 transition-colors"
              >
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center space-x-2 mb-2">
                      <h3 className="text-sm font-medium text-gray-900">{complaint.title}</h3>
                      <span className={`status-badge ${getStatusClass(complaint.status)}`}>
                        {complaint.status.toLowerCase().replace('_', ' ')}
                      </span>
                      <span className={`status-badge ${getPriorityClass(complaint.priority)}`}>
                        {complaint.priority.toLowerCase()}
                      </span>
                    </div>
                    <p className="text-sm text-gray-600 line-clamp-2">{complaint.description}</p>
                    <div className="flex items-center space-x-4 mt-2 text-xs text-gray-500">
                      <div className="flex items-center space-x-1">
                        <Calendar className="h-3 w-3" />
                        <span>{new Date(complaint.createdAt).toLocaleDateString()}</span>
                      </div>
                      {complaint.blockNumber && (
                        <span>Block: {complaint.blockNumber}</span>
                      )}
                      {complaint.roomNumber && (
                        <span>Room: {complaint.roomNumber}</span>
                      )}
                    </div>
                  </div>
                  <div className="flex items-center space-x-2 ml-4">
                    {getStatusIcon(complaint.status)}
                    <Link
                      to={`/complaints/${complaint.id}`}
                      className="text-primary-600 hover:text-primary-500 text-sm font-medium"
                    >
                      View
                    </Link>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default UserDashboard;
